mapper.select:
SELECT conversation_id AS conversationId, title, tag, mode, pinned, summary, last_message AS lastMessage, last_time AS lastTime, create_time AS createTime, message_count AS messageCount FROM conversation_info WHERE user_id = #{userId}
AND mode = #{mode}
AND ( LOWER(IFNULL(title, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(IFNULL(summary, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(IFNULL(last_message, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%') )
ORDER BY pinned DESC, last_time DESC, update_time DESC

SELECT c.conversation_id AS conversationId, c.user_id AS userId, u.userName AS userName, c.title, c.mode, c.tag, c.pinned, c.summary AS summary, c.last_message AS lastMessage, c.create_time AS createTime, c.last_time AS lastTime, c.message_count AS messageCount FROM conversation_info c LEFT JOIN user u ON u.id = c.user_id WHERE 1 = 1
AND c.mode = #{mode}
AND c.pinned = #{pinned}
AND ( LOWER(IFNULL(c.title, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(IFNULL(u.userName, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%') )
ORDER BY c.pinned DESC, c.last_time DESC, c.update_time DESC LIMIT #{limit}
